import{_ as e,o as t,c as i,ae as l}from"./chunks/framework.Czhw_PXq.js";const _=JSON.parse('{"title":"双指针算法概述","description":"","frontmatter":{"title":"双指针算法概述","icon":"arrows"},"headers":[],"relativePath":"posts/algorithm/twoPointers/index.md","filePath":"posts/algorithm/twoPointers/index.md","lastUpdated":null}'),r={name:"posts/algorithm/twoPointers/index.md"};function o(n,a,s,h,d,c){return t(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="双指针算法概述" tabindex="-1">双指针算法概述 <a class="header-anchor" href="#双指针算法概述" aria-label="Permalink to &quot;双指针算法概述&quot;">​</a></h1><p>双指针（Two Pointers）是一种在数组或链表中使用两个指针协同工作的技巧，常用于优化时间复杂度或空间复杂度。根据指针移动方式不同，可分为<strong>同向双指针</strong>（快慢指针）和<strong>相向双指针</strong>（左右指针）。</p><h2 id="常见类型" tabindex="-1">常见类型 <a class="header-anchor" href="#常见类型" aria-label="Permalink to &quot;常见类型&quot;">​</a></h2><h3 id="_1-相向双指针-左右指针" tabindex="-1">1. 相向双指针（左右指针） <a class="header-anchor" href="#_1-相向双指针-左右指针" aria-label="Permalink to &quot;1. 相向双指针（左右指针）&quot;">​</a></h3><ul><li>从数组两端向中间移动</li><li>典型应用：两数之和（有序数组）、接雨水、回文判断</li></ul><h3 id="_2-同向双指针-快慢指针" tabindex="-1">2. 同向双指针（快慢指针） <a class="header-anchor" href="#_2-同向双指针-快慢指针" aria-label="Permalink to &quot;2. 同向双指针（快慢指针）&quot;">​</a></h3><ul><li>两个指针从同一方向出发，速度不同</li><li>典型应用：链表中检测环、移除重复元素、滑动窗口</li></ul><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li>时间复杂度通常为 O(n)</li><li>空间复杂度可降至 O(1)</li><li>代码简洁高效</li></ul><h2 id="经典题型" tabindex="-1">经典题型 <a class="header-anchor" href="#经典题型" aria-label="Permalink to &quot;经典题型&quot;">​</a></h2><ul><li><a href="./receiveRainWater.html">接雨水</a></li></ul><p>双指针技巧广泛应用于字符串处理、数组操作及滑动窗口类问题，是解决线性结构问题的重要工具。</p>',12)])])}const m=e(r,[["render",o]]);export{_ as __pageData,m as default};
